const sp=$input.first().json; const nq=$input.last().json; const m=new Map();
if(Array.isArray(sp)){for(const i of sp) m.set(i.symbol,{ticker:i.symbol,company_name:i.name,sector:i.sector||'Unknown',industry:i.subSector||i.sector||'Unknown',exchange:i.exchange||'NYSE',index_membership:['SP500']});}
if(Array.isArray(nq)){for(const i of nq){if(m.has(i.symbol))m.get(i.symbol).index_membership.push('NASDAQ100'); else m.set(i.symbol,{ticker:i.symbol,company_name:i.name,sector:i.sector||'Unknown',industry:i.subSector||i.sector||'Unknown',exchange:i.exchange||'NASDAQ',index_membership:['NASDAQ100']});}}
return Array.from(m.values()).map(t=>({json:t}));
